import React, { useEffect, useState, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { experiencesService } from '../services/experiences';
import { coursesService } from '../services/courses';
import { authService } from '../services/auth';

export default function CreateExperience() {
  const navigate = useNavigate();
  const [sectionsList, setSectionsList] = useState([]); // قائمة منبسطة للسكاشن
  const [loading, setLoading] = useState(false);
  const [fetching, setFetching] = useState(true);

  const [form, setForm] = useState({
    section: '',
    title: '',
    description: '',
    price: '0',
    instructor_cut: '70',
    college_cut: '30',
    status: 'draft',
  });

  const [imageFile, setImageFile] = useState(null);
  const [errors, setErrors] = useState({});

  // دالة جلب البيانات معالجة بشكل صحيح
  const loadData = useCallback(async () => {
    try {
      setFetching(true);
      const data = await coursesService.getAll();
      const list = data.results ?? data;

      const allSections = [];
      list.forEach(course => {
        if (course.sections && course.sections.length > 0) {
          course.sections.forEach(sec => {
            allSections.push({
              id: sec.id,
              label: `${course.title} ⮕ ${sec.title}`
            });
          });
        }
      });
      setSectionsList(allSections);
    } catch (err) {
      console.error("Fetch error:", err);
    } finally {
      setFetching(false);
    }
  }, []);

  useEffect(() => {
    const user = authService.getUserFromStorage();
    if (!user?.is_instructor) {
      navigate('/experiences');
      return;
    }
    loadData();
  }, [navigate, loadData]);

  const handle = (e) => {
    const { name, value, files } = e.target;
    if (name === 'image') {
      setImageFile(files[0]);
    } else {
      setForm(f => {
        const newForm = { ...f, [name]: value };
        if (name === 'instructor_cut') {
          const ic = Math.min(100, Math.max(0, parseFloat(value) || 0));
          newForm.instructor_cut = String(ic);
          newForm.college_cut = String(100 - ic);
        }
        return newForm;
      });
    }
  };

  const submit = async (e, publishNow = false) => {
    e.preventDefault();
    setLoading(true);
    try {
      const formData = new FormData();
      Object.keys(form).forEach(key => {
        if (key === 'status') formData.append(key, publishNow ? 'published' : 'draft');
        else formData.append(key, form[key]);
      });
      if (imageFile) formData.append('image', imageFile);

      await experiencesService.create(formData);
      alert('تم الحفظ بنجاح');
      navigate('/experiences');
    } catch (err) {
      setErrors(err.response?.data || {});
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={s.page}>
      <div style={s.container}>
        <h1 style={s.title}>إضافة تجربة جديدة 🧪</h1>
        <form style={s.form}>

          <Field label="اختر السكشن المرتبط" error={errors.section}>
            <select 
              name="section" 
              value={form.section} 
              onChange={handle} 
              style={s.select}
            >
              <option value="">-- تجربة عامة (بدون سكشن) --</option>
              {sectionsList.map(sec => (
                <option key={sec.id} value={sec.id}>
                  {sec.label}
                </option>
              ))}
            </select>
            {fetching && <p style={{fontSize:'0.7rem', color:'#c8973a'}}>جاري تحميل السكاشن...</p>}
          </Field>

          <Field label="عنوان التجربة" error={errors.title}>
            <input name="title" value={form.title} onChange={handle} style={s.input} placeholder="مثال: شرح المعمل الأول" />
          </Field>

          <Field label="الوصف" error={errors.content}>
            <textarea name="description" value={form.description} onChange={handle} style={{...s.input, height: 100}} />
          </Field>

          <div style={s.row}>
            <Field label="السعر" style={{flex:1}}>
              <input type="number" name="price" value={form.price} onChange={handle} style={s.input} />
            </Field>
            <Field label="الصورة" style={{flex:1}}>
              <input type="file" name="image" onChange={handle} style={s.input} />
            </Field>
          </div>

          <div style={s.btnRow}>
            <button type="button" onClick={(e)=>submit(e, false)} style={s.btnDraft} disabled={loading}>حفظ مسودة</button>
            <button type="button" onClick={(e)=>submit(e, true)} style={s.btnPublish} disabled={loading}>نشر الآن</button>
          </div>
        </form>
      </div>
    </div>
  );
}

// الستايلات (نفس اللي عندك)
const s = {
  page: { background: '#0a0a0f', minHeight: '100vh', padding: '40px 20px', color: '#e8e8f0', direction: 'rtl' },
  container: { maxWidth: 600, margin: '0 auto' },
  title: { textAlign: 'center', marginBottom: '2rem' },
  form: { background: '#16161f', padding: '2rem', borderRadius: 8, border: '1px solid #2a2a38' },
  input: { width: '100%', background: '#111118', border: '1px solid #2a2a38', padding: '12px', color: '#fff', marginBottom: '10px', borderRadius: 4 },
  select: { width: '100%', background: '#111118', border: '1px solid #2a2a38', padding: '12px', color: '#fff', borderRadius: 4 },
  row: { display: 'flex', gap: '15px' },
  btnRow: { display: 'flex', gap: '15px', marginTop: '20px' },
  btnDraft: { flex: 1, background: 'transparent', border: '1px solid #c8973a', color: '#c8973a', padding: '12px', cursor: 'pointer' },
  btnPublish: { flex: 1, background: '#c8973a', border: 'none', color: '#000', padding: '12px', cursor: 'pointer', fontWeight: 'bold' }
};

function Field({ label, error, children, style }) {
  return (
    <div style={{ marginBottom: '1rem', ...style }}>
      <label style={{ display: 'block', color: '#c8973a', fontSize: '0.8rem', marginBottom: '5px' }}>{label}</label>
      {children}
      {error && <p style={{ color: '#e94560', fontSize: '0.7rem' }}>{String(error)}</p>}
    </div>
  );
}
